 	SELECT  'DPSD' || LPAD(nextval('DEPT_SCHD_ID_SEQ')::text, 12, '0')

INSERT INTO DEPARTMENT_SCHEDULE(
	DEPT_SCHD_ID
	, DEPT_ID	
	, SCHD_STRT_DT
	, SCHD_END_DT
	, DEPT_SCHD_CRT_USER_ID
	, SCHD_TTL
	, ALLDAY
	, DEPT_SCHD_EXPLN			
) VALUES (
	#{deptSchdId}
	, #{deptId}
	, #{schdStrtDt}
	, #{schdEndDt}
	, #{deptSchdCrtUserId}
	, #{schdTtl}
	, #{allday}
	, #{deptSchdExpln}
)

