UPDATE DEPARTMENT_SCHEDULE
SET 
	SCHD_TTL = #{schdTtl}
	, SCHD_STRT_DT = #{schdStrtDt}
	, SCHD_END_DT = #{schdEndDt}
	, ALLDAY = #{allday}
	, DEPT_SCHD_EXPLN = #{deptSchdExpln}
	, DEL_YN = #{delYn}
WHERE 
	DEPT_SCHD_ID = #{deptSchdId}

UPDATE DEPARTMENT_SCHEDULE
SET DEL_YN = 'Y'
WHERE DEPT_SCHD_ID = #{deptSchdId}
